# RawrXD Final Integration — Instantiation Sequence + Global Context Implementation
# Completes the circular architecture: 12 generators → runtime wiring → single entry point

# ═══════════════════════════════════════════════════════════════════════════════
# 1. GLOBAL CONTEXT IMPLEMENTATION (Expanded singleton with all 7 subsystems)
# ═══════════════════════════════════════════════════════════════════════════════

Set-Content -Path "src/GlobalContext_Expanded.cpp" -Value @'
#include "GlobalContextExpanded.h"
#include "security/SecureHotpatchOrchestrator.h"
#include "UnifiedToolRegistry.h"
#include "EventBus.h"
#include "HotpatchBridgeUnified.h"
#include "CompilerAgentBridge.h"
#include "PerformanceMonitor.h"

namespace RawrXD {
GlobalContext& GlobalContext::Instance() { static GlobalContext i; return i; }
void GlobalContext::Initialize() {
    m_perfMon = std::make_unique<PerformanceMonitor>();
    m_perfMon->Initialize();
    m_eventBus = std::make_unique<EventBus>();
    m_toolRegistry = std::make_unique<UnifiedToolRegistry>();
    m_hotpatch = std::make_unique<HotPatcher>();
    m_securePatcher = std::make_unique<SecureHotpatchOrchestrator>(&m_rbac, m_hotpatch.get());
    m_compilerBridge = std::make_unique<CompilerAgentBridge>();
    m_lspCore = std::make_unique<LSPCore>();
    m_perfMon->StartTracking();
}
void GlobalContext::Shutdown() {
    if(m_perfMon) m_perfMon->Shutdown();
    if(m_hotpatch) m_hotpatch->Shutdown();
}
EventBus* GlobalContext::GetEventBus() { return m_eventBus.get(); }
UnifiedToolRegistry* GlobalContext::GetToolRegistry() { return m_toolRegistry.get(); }
HotPatcher* GlobalContext::GetHotPatcher() { return m_hotpatch.get(); }
SecureHotpatchOrchestrator* GlobalContext::GetSecurePatcher() { return m_securePatcher.get(); }
CompilerAgentBridge* GlobalContext::GetCompilerBridge() { return m_compilerBridge.get(); }
LSPCore* GlobalContext::GetLSPCore() { return m_lspCore.get(); }
PerformanceMonitor* GlobalContext::GetPerfMon() { return m_perfMon.get(); }
RBAC::RBACEngine* GlobalContext::GetRBAC() { return &m_rbac; }
} // namespace RawrXD
'@

# ═══════════════════════════════════════════════════════════════════════════════
# 2. WIN32IDE INITIALIZATION SEQUENCE (Correct instantiation order)
# ═══════════════════════════════════════════════════════════════════════════════

Set-Content -Path "win32app/Win32IDE_InitSequence.cpp" -Value @'
#include "Win32IDE.h"
#include "GlobalContextExpanded.h"
#include "EventBus.h"
#include "beacon/BeaconClient.h"
#include "beacon/gui_pane_beacon_wiring.h"

namespace RawrXD {
bool Win32IDE::InitializeSubsystemStack() {
    // Phase 0: Global Context (singletons)
    GlobalContext::Instance().Initialize();
    m_eventBus = GlobalContext::Instance().GetEventBus();
    
    // Phase 1: Beacon Circular System (before GUI, after context)
    m_beacon = std::make_unique<BeaconClient>(L"localhost", 9001);
    if(!m_beacon->Start()) { OutputDebugStringA("Beacon failed\n"); return false; }
    m_beaconWiring = std::make_unique<GUIPaneBeaconWiring>(m_beacon.get());
    
    // Phase 2: Core IDE Window (Win32, Qt-free)
    if(!CreateMainWindow()) return false;
    
    // Phase 3: Dock Widgets (5 rebased components)
    RECT dockRect = {0, 0, 300, 400};
    m_todoDock = std::make_unique<TodoDock>();
    m_todoDock->Create(this, dockRect);
    m_todoDock->Show();
    
    m_observability = std::make_unique<ObservabilityDashboard>();
    m_observability->Create(this, dockRect);
    
    m_trainingDialog = std::make_unique<TrainingDialog>();
    m_trainingDialog->Create(this, dockRect);
    
    m_modelRouter = std::make_unique<ModelRouterWidget>();
    m_modelRouter->Create(this, dockRect);
    
    // Phase 4: Secure Hotpatch Orchestrator
    m_securePatcher = GlobalContext::Instance().GetSecurePatcher();
    m_hotpatchPanel = std::make_unique<Win32IDE_HotpatchPanel>();
    m_hotpatchPanel->Create(this);
    m_hotpatchPanel->SetSecurePatcher(m_securePatcher);
    
    // Phase 5: Beacon Wiring to GUI Panes (circular connectivity)
    m_beaconWiring->WireTodoDock(m_todoDock.get());
    m_beaconWiring->WireObservability(m_observability.get());
    m_beaconWiring->WireTraining(m_trainingDialog.get());
    m_beaconWiring->WireModelRouter(m_modelRouter.get());
    m_beaconWiring->WireSecurityBridge(m_securePatcher);
    
    // Phase 6: EventBus Subscriptions (cross-component signals)
    WireEventBusSubscriptions();
    
    // Phase 7: Agentic Systems
    m_agentOrchestrator = std::make_unique<Agent::AgentOrchestrator>();
    m_agentOrchestrator->SetToolRegistry(GlobalContext::Instance().GetToolRegistry());
    m_agentOrchestrator->SetEventBus(m_eventBus);
    
    // Phase 8: LSP Core
    m_lspCore = GlobalContext::Instance().GetLSPCore();
    m_lspCore->Initialize();
    
    // Phase 9: Performance Monitoring
    m_perfMon = GlobalContext::Instance().GetPerfMon();
    m_perfMon->onMetricCaptured.connect([this](const std::string& name, float val){
        m_observability->AddMetric(std::wstring(name.begin(), name.end()), val);
    });
    
    // Phase 10: Final Layout
    UpdateLayout();
    ShowWindow(nativeHandle(), SW_SHOW);
    SetStatusText(L"RawrXD Circular Beacon System Online — Qt-Free");
    return true;
}
void Win32IDE::WireEventBusSubscriptions() {
    // Editor → Agentic
    m_eventBus->Subscribe("editor:text_changed", [this](const Event& e){
        m_agentOrchestrator->NotifyContextChange(e.GetString("file"));
    });
    // Agentic → Hotpatch (circular)
    m_eventBus->Subscribe("agentic:patch_required", [this](const Event& e){
        std::vector<uint8_t> code = e.GetBinary("patch_data");
        m_securePatcher->RequestPatch(e.GetString("patch_id"), code, L"agentic_system");
    });
    // Hotpatch → Security (audit)
    m_eventBus->Subscribe("hotpatch:applied", [this](const Event& e){
        m_eventBus->Publish("security:audit_log", {
            {"action", "hotpatch"},
            {"id", e.GetString("patch_id")},
            {"timestamp", std::to_string(GetTickCount64())}
        });
    });
    // Compiler ↔ Agentic bridge
    m_eventBus->Subscribe("compiler:build_complete", [this](const Event& e){
        if(e.GetBool("success")) {
            m_agentOrchestrator->NotifyBuildSuccess(e.GetString("output"));
        }
    });
    // Beacon circular routing
    m_beacon->MessageSignal().connect([this](const BeaconMessage& msg){
        if(msg.command == L"eventbus:publish") {
            m_eventBus->Publish("beacon:" + std::string(msg.command.begin(), msg.command.end()), {});
        }
    });
}
void Win32IDE::UpdateLayout() {
    RECT rc; GetClientRect(nativeHandle(), &rc);
    int sidebarW = 250;
    int bottomH = 200;
    // Layout docks in circular arrangement around center editor
    HDWP dwp = BeginDeferWindowPos(5);
    DeferWindowPos(dwp, m_todoDock->nativeHandle(), NULL, 0, 0, sidebarW, rc.bottom-bottomH, SWP_NOZORDER);
    DeferWindowPos(dwp, m_observability->nativeHandle(), NULL, rc.right-sidebarW, 0, sidebarW, rc.bottom-bottomH, SWP_NOZORDER);
    DeferWindowPos(dwp, m_trainingDialog->nativeHandle(), NULL, 0, rc.bottom-bottomH, sidebarW, bottomH, SWP_NOZORDER);
    DeferWindowPos(dwp, m_modelRouter->nativeHandle(), NULL, rc.right-sidebarW, rc.bottom-bottomH, sidebarW, bottomH, SWP_NOZORDER);
    EndDeferWindowPos(dwp);
}
} // namespace RawrXD
'@

# ═══════════════════════════════════════════════════════════════════════════════
# 3. WINMAIN ENTRY POINT (Qt-free bootstrap)
# ═══════════════════════════════════════════════════════════════════════════════

Set-Content -Path "src/WinMain.cpp" -Value @'
#include <windows.h>
#include "win32app/Win32IDE.h"
#include "GlobalContextExpanded.h"
#pragma comment(linker, "/SUBSYSTEM:WINDOWS")

int WINAPI wWinMain(HINSTANCE hInst, HINSTANCE, LPWSTR, int nCmdShow) {
    // COM for shell/DragDrop (Qt-free)
    CoInitializeEx(NULL, COINIT_APARTMENTTHREADED);
    
    // Global context singleton bootstrap
    RawrXD::GlobalContext::Instance().Initialize();
    
    // IDE instantiation
    RawrXD::Win32IDE ide;
    if(!ide.InitializeSubsystemStack()) {
        MessageBoxW(NULL, L"Circular Beacon System Failed", L"RawrXD Fatal", MB_ICONERROR);
        return 1;
    }
    
    // Main message pump (Win32, not Qt QApplication)
    MSG msg;
    while(GetMessageW(&msg, NULL, 0, 0)) {
        if(!IsDialogMessageW(ide.nativeHandle(), &msg)) {
            TranslateMessage(&msg);
            DispatchMessageW(&msg);
        }
    }
    
    // Circular shutdown sequence
    ide.Shutdown();
    RawrXD::GlobalContext::Instance().Shutdown();
    CoUninitialize();
    return (int)msg.wParam;
}
'@

# ═══════════════════════════════════════════════════════════════════════════════
# 4. EVENTBUS SUBSCRIPTION SETUP (Explicit cross-component wiring)
# ═══════════════════════════════════════════════════════════════════════════════

Set-Content -Path "src/EventBus_Wiring.cpp" -Value @'
#include "EventBus.h"
#include "win32app/Win32IDE.h"
#include "agentic/AgentOrchestrator.h"
#include "security/SecureHotpatchOrchestrator.h"

void RawrXD::Win32IDE::InitializeEventBusWiring() {
    // Circular Beacon: IDE → Agentic → Hotpatch → Security → IDE
    m_eventBus->Subscribe("beacon:agentic_command", [this](const Event& e){
        m_agentOrchestrator->ExecuteCommand(e.GetString("cmd"));
    });
    m_eventBus->Subscribe("beacon:hotpatch_request", [this](const Event& e){
        auto perms = m_securePatcher->GetRBAC()->CheckPermission(L"beacon_system", L"hotpatch:apply");
        if(perms) {
            m_securePatcher->RequestPatch(e.GetString("id"), e.GetBinary("code"), L"beacon_system");
        }
    });
    m_eventBus->Subscribe("beacon:security_audit", [this](const Event& e){
        // Circular completion: security reports back to IDE
        SetStatusText(std::wstring(e.GetString("status").begin(), e.GetString("status").end()));
    });
    // GUI Pane → Beacon → Agentic (circular shortcuts)
    m_todoDock->onTodoAdded.connect([this](const std::wstring& text){
        m_eventBus->Publish("gui:todo_added", {{"text", std::string(text.begin(), text.end())}});
        m_beacon->Send(BeaconType::Agentic, L"todo:add", std::vector<uint8_t>(text.begin(), text.end()));
    });
}
'@

# ═══════════════════════════════════════════════════════════════════════════════
# 5. CMAKE INTEGRATION (Final linkage check)
# ═══════════════════════════════════════════════════════════════════════════════

Add-Content -Path "CMakeLists.txt" -Value @'
# RawrXD Qt-Free Integration (Auto-generated)
add_executable(RawrXD-QtFree 
    src/WinMain.cpp
    src/GlobalContext_Expanded.cpp
    win32app/Win32IDE_InitSequence.cpp
    src/EventBus_Wiring.cpp
    ${BEACON_CLIENT_SRC}
    ${DOCK_WIDGET_SRC}
    ${SECURITY_SRC}
    ${AGENTIC_SRC}
    ${LSP_SRC}
)
target_link_libraries(RawrXD-QtFree 
    d2d1 dwrite comctl32 winhttp pdh 
    # Explicitly NO Qt6::Core, NO Qt6::Widgets, NO Qt6::Gui
)
target_compile_definitions(RawrXD-QtFree PRIVATE 
    RAWRXD_QT_FREE=1 
    CIRCULAR_BEACON_ENABLED=1
    _WIN32_WINNT=0x0A00
)
'@

Write-Host "✅ FINAL INTEGRATION COMPLETE — 12 generators → runtime instantiation → circular beacon" -ForegroundColor Green
Write-Host "🔄 Bootstrap Order: Context → Beacon → GUI → Hotpatch → Agentic → LSP → PerfMon" -ForegroundColor Cyan
Write-Host "🚫 Zero Qt dependencies — Pure Win32/D2D/SignalSlot architecture" -ForegroundColor Yellow
Write-Host "🎯 Entry Point: WinMain.cpp → Win32IDE::InitializeSubsystemStack()" -ForegroundColor White
```'
